<?php
declare(strict_types=1);
if(PHP_SAPI!=='cli'){exit(2);}require_once dirname(__DIR__).'/lib/config.php';require_once dirname(__DIR__).'/lib/Database.php';
$pdo=new PDO(DB_DSN,DB_USERNAME,DB_PASSWORD,[PDO::ATTR_ERRMODE=>PDO::ERRMODE_EXCEPTION]);$admin=$pdo->query("SELECT u_id FROM user_tbl WHERE u_type=1 AND avail_status=1 ORDER BY u_id LIMIT 1")->fetchColumn();if(!is_string($admin)||$admin===''){exit(1);}
$op=new Database();$cid=bin2hex(random_bytes(8));$factor=0;$ok=false;$replay=-1;
try{$op->beginTransaction();$factor=$op->admin_mfa_create_pending_factor(['admin_user_id'=>$admin,'encrypted_secret'=>random_bytes(48),'secret_nonce'=>random_bytes(24),'key_version'=>'contract','device_label'=>'F7.3 rollback contract','created_by'=>$admin,'correlation_id'=>$cid,'enrollment_session_hash'=>hash('sha256','session'),'enrollment_browser_digest'=>hash('sha256','browser')]);$row=$op->admin_mfa_factor_for_update($factor);$confirmed=$op->admin_mfa_confirm_factor($factor,100);$used=$op->admin_mfa_record_factor_use($factor,101);$replay=$op->admin_mfa_record_factor_use($factor,101);$revoked=$op->admin_mfa_revoke_factor($factor);$ok=is_array($row)&&$row['factor_status']==='PENDING'&&$confirmed===1&&$used===1&&$replay===0&&$revoked===1;}finally{$op->rollback();}
$q=$pdo->prepare('SELECT COUNT(*) FROM admin_mfa_factors WHERE correlation_id=:cid');$q->execute([':cid'=>$cid]);$remaining=(int)$q->fetchColumn();printf("%s lifecycle=%s replay_blocked=%s rollback_remaining=%d persistent_mutations=0\n",$ok&&$remaining===0?'PASS':'FAIL',$ok?'yes':'no',$replay===0?'yes':'no',$remaining);exit($ok&&$remaining===0?0:1);
